<?php
$pageTitle='Product Bundles';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('product_bundles');
$pdo=getDB();$products=$pdo->query('SELECT id,sku,name,price FROM '.table('products').' WHERE active=1 ORDER BY name LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)($_POST['action']??'bundle');if($action==='item'){ecom33AddBundleItem($pdo,(int)$_POST['product_bundle_id'],(int)$_POST['product_id'],(float)$_POST['quantity'],$_POST['unit_price']!==''?(float)$_POST['unit_price']:null);flash('success','Bundle item added.');}else{ecom33CreateBundle($pdo,$_POST);flash('success','Product bundle created.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'product-bundles']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/product-bundles.php');}
$bundles=$pdo->query('SELECT * FROM '.table('product_bundles').' ORDER BY created_at DESC LIMIT 200')->fetchAll();
$items=$pdo->query('SELECT bi.*,b.bundle_number,b.bundle_name,p.name product_name,p.sku FROM '.table('product_bundle_items').' bi LEFT JOIN '.table('product_bundles').' b ON b.id=bi.product_bundle_id LEFT JOIN '.table('products').' p ON p.id=bi.product_id ORDER BY bi.created_at DESC LIMIT 300')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Kit & Offer Builder</div><h2 class="h4 mb-1">Product Bundles</h2><p class="text-secondary mb-0">Build scanner bundles, diagnostic kits, software bundles, accessory packs and service packages.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Bundle</h2><input class="form-control mb-2" name="bundle_name" placeholder="Workshop Diagnostic Kit" required><input class="form-control mb-2" name="slug" placeholder="auto slug"><textarea class="form-control mb-2" name="description" rows="3"></textarea><input class="form-control mb-2" type="number" step="0.01" name="bundle_price" placeholder="Bundle price"><input class="form-control mb-2" type="number" step="0.01" name="compare_price" placeholder="Compare price"><input class="form-control mb-2" type="number" step="0.01" name="total_cost" placeholder="Total cost"><select class="form-select mb-2" name="status"><option>active</option><option>inactive</option></select><select class="form-select mb-3" name="featured"><option value="0">Not featured</option><option value="1">Featured</option></select><button class="btn btn-brand w-100">Create Bundle</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="item"><h2 class="h5 mb-3">Add Bundle Item</h2><select class="form-select mb-2" name="product_bundle_id"><?php foreach($bundles as $b): ?><option value="<?php echo (int)$b['id']; ?>"><?php echo esc($b['bundle_number'].' · '.$b['bundle_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name'].' · '.money($p['price'])); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" step="0.01" name="quantity" value="1"><input class="form-control mb-3" type="number" step="0.01" name="unit_price" placeholder="Leave blank for product price"><button class="btn btn-outline-primary w-100">Add Item</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Bundles</h2><table class="table"><thead><tr><th>Bundle</th><th>Price</th><th>Status</th></tr></thead><tbody><?php foreach($bundles as $b): ?><tr><td><strong><?php echo esc($b['bundle_number']); ?></strong><div class="small text-secondary"><?php echo esc($b['bundle_name']); ?></div></td><td><?php echo money($b['bundle_price']); ?><div class="small text-secondary">Compare <?php echo money($b['compare_price']); ?></div></td><td><span class="badge bg-<?php echo esc(statusTone($b['status'])); ?>"><?php echo esc($b['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Bundle Items</h2><table class="table"><thead><tr><th>Bundle</th><th>Product</th><th>Qty</th><th>Total</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['bundle_number']); ?><div class="small text-secondary"><?php echo esc($i['bundle_name']); ?></div></td><td><?php echo esc($i['sku'].' · '.$i['product_name']); ?></td><td><?php echo esc($i['quantity']); ?></td><td><?php echo money($i['line_total']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
